let triggerTime = parseFloat(msg.payload); // Zeit in Sekunden aus dem input
let timerId = flow.get('timerId') || null; // Holen des Timer-IDs aus dem Flow-Kontext
let endTime = flow.get('endTime') || Date.now() + triggerTime * 1000; // Endzeit aus Flow-Kontext oder neu berechnen

// Bestehenden Timer löschen, falls vorhanden
if (timerId) {
    clearInterval(timerId);
}

// Funktion zur Aktualisierung des Node-Status
function updateCountdown() {
    let remainingTime = Math.ceil((endTime - Date.now()) / 1000);
    if (remainingTime > 0) {
        node.status({fill:"red", shape:"ring", text:`Trigger in ${remainingTime}s`});
    } else {
        node.status({fill:"green", shape:"dot", text:"Triggered"});
        endTime = Date.now() + triggerTime * 1000; // Neu berechnen des Endzeitpunkts für kontinuierliche Wiederholungen
        node.send({payload: true}); // Sende 'true' bei Ablauf des Timers
    }
}

// Setzen des Intervall-Timers
timerId = setInterval(() => {
    updateCountdown();
}, 1000); // Jede Sekunde aktualisieren

// Speichern des Timer-IDs und des Endzeitpunkts im Flow-Kontext
flow.set('timerId', timerId);
flow.set('endTime', endTime);

// Initialer Aufruf zur Statusaktualisierung
updateCountdown();

return null; // Keine direkte Nachrichtenausgabe

// Definier Funktion zur Erstellung der Log-Nachricht
function createLogFileMsg(dtuState, invStateProducing, invStateReachable, statusZeroInjection, pwrConsumption, pwrSecondSource, socLevelBattery, setPercentMsg, turnOnMsg, turnOffMsg, debugMsg) {
    const now = new Date();
    const formattedTime = now.toLocaleString('de-DE', { hour12: false }); // Formatiert Zeit als 'Tag.Monat.Jahr Stunden:Minuten:Sekunden'

    // Konvertiert Zahlenwerte zu Strings mit Komma als Dezimaltrennzeichen
    const formattedPwrConsumption = pwrConsumption.toLocaleString('de-DE');
    const formattedPwrSecondSource = pwrSecondSource.toLocaleString('de-DE');

    return {
        payload: {
            "time": formattedTime,
            "dtuState": dtuState,
            "invStateProducing": invStateProducing,
            "invStateReachable": invStateReachable,
            "statusZeroInjection": statusZeroInjection,
            "pwrConsumption": formattedPwrConsumption,
            "pwrSecondSource": formattedPwrSecondSource,
            "socLevelBattery": socLevelBattery,
            "setPercentMsg": setPercentMsg ? setPercentMsg.payload : null,
            "turnOnMsg": turnOnMsg ? turnOnMsg.payload : null,
            "turnOffMsg": turnOffMsg ? turnOffMsg.payload : null,
            "debugMsg": debugMsg.payload
        }
    };
}

// Definiert min und max Prozentwerte für die DTU-Ausgangsleistung
const maxOutputPowerInv = parseFloat(msg.payload.maxOutputPowerInv); // Maximale Ausgangsleistung des Wechselrichters in Watt
const pwrSteps = maxOutputPowerInv / 100; // Berechnet die Leistung pro Prozent
const minOutputZeroInjection = parseFloat(msg.payload.minOutputZeroInjection); // Minimale Leistung in Prozent bei aktivierter Nulleinspeisung
const maxOutputZeroInjection = parseFloat(msg.payload.maxOutputZeroInjection); // Maximale Leistung in Prozent bei aktivierter Nulleinspeisung
const maxOutputAtFullSoc = parseFloat(msg.payload.maxOutputAtFullSoc); // Maximale Ausgangsleistung in Prozent bei vollem Batterie-SoC
const staticInverterOutputPower = parseFloat(msg.payload.staticInverterOutputPower); // Voreingestellte Ausgangsleistung, wenn Nulleinspeisung deaktiviert ist
const minPowerInverter = minOutputZeroInjection * pwrSteps; // Berechnet die minimale Leistung in Watt, basierend auf dem Prozentwert und den Leistungsschritten

// Definiert Schwellenwerte für den Batterie-SoC
const offThresholdInv = parseFloat(msg.payload.offThresholdInv); // Batterie-SoC-Schwelle zum Ausschalten des Wechselrichters
const onThresholdInv = parseFloat(msg.payload.onThresholdInv); // Batterie-SoC-Schwelle zum Einschalten des Wechselrichters

// Extrahiert Daten aus msg.payload für Steuerungsentscheidungen
const dtuState = msg.payload.dtuState; // Der aktuelle Betriebszustand der DTU (Datenübertragungseinheit)
const pwrSecondSource = parseFloat(msg.payload.pwrSecondSource); // Leistung der zweiten Energiequelle in Watt
const pwrConsumption = parseFloat(msg.payload.pwrConsumption); // Aktueller Gesamtstromverbrauch in Watt
const invStateProducing = msg.payload.invStateProducing; // Gibt an, ob der Wechselrichter aktuell Strom produziert
const invStateReachable = msg.payload.invStateReachable; // Verfügbarkeitsstatus des Wechselrichters
const socLevelBattery = parseFloat(msg.payload.socLevelBattery); // Der aktuelle Ladezustand der Batterie in Prozent
const statusZeroInjection = msg.payload.statusZeroInjection; // Aktueller Status der Nulleinspeisung ('on' oder 'off')

// Entscheidungslogik für die Ausgabe der Befehle basierend auf dem Zustand und den Messdaten
let setPercentMsg = null;
let turnOnMsg = null;
let turnOffMsg = null;
let debugMsg = null;

// Steuerung basierend auf dem Status der Nulleinspeisung
if (statusZeroInjection !== "on") {
    if (invStateProducing === "on") {
        setPercentMsg = { payload: staticInverterOutputPower };
        debugMsg = { payload: "Nulleinspeisung deaktiviert, statische Leistung angewendet" };
    } else {
        debugMsg = { payload: "Nulleinspeisung deaktiviert, Wechselrichter aus" };
    }
    const logFileMsg = createLogFileMsg(dtuState, invStateProducing, invStateReachable, statusZeroInjection, pwrConsumption, pwrSecondSource, socLevelBattery, setPercentMsg, turnOnMsg, turnOffMsg, debugMsg);
    return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];
} else {
    debugMsg = { payload: "Nulleinspeisung aktiviert" };
}

// Überprüft die Erreichbarkeit und Betriebsbereitschaft der Systemkomponenten
if (dtuState !== "on" || invStateReachable !== "on") {
    debugMsg = { payload: `DTU offline oder Wechselrichter nicht erreichbar` };
    const logFileMsg = createLogFileMsg(dtuState, invStateProducing, invStateReachable, statusZeroInjection, pwrConsumption, pwrSecondSource, socLevelBattery, setPercentMsg, turnOnMsg, turnOffMsg, debugMsg);
    return [null, null, null, debugMsg, logFileMsg];
} else {
    debugMsg = { payload: `DTU und Wechselrichter sind online` };
}

// Berechnet die erforderliche Leistungskorrektur basierend auf dem aktuellen Verbrauch und der Zweitquelle
let powerDifference = pwrConsumption - pwrSecondSource;

// Steuerung des Wechselrichters basierend auf dem Batterie-SoC und der Differenzleistung
if (socLevelBattery <= offThresholdInv && invStateProducing === "on") {
    turnOffMsg = { payload: "OFF" };
    const logFileMsg = createLogFileMsg(dtuState, invStateProducing, invStateReachable, statusZeroInjection, pwrConsumption, pwrSecondSource, socLevelBattery, setPercentMsg, turnOnMsg, turnOffMsg, debugMsg);
    return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];
} else {
    // Zuerst wird überprüft, ob der Wechselrichter Strom produziert
    if (invStateProducing === "on") {
        if (powerDifference < minPowerInverter) {
            // Sendet ein Signal, um den Wechselrichter auszuschalten, falls die Differenzleistung unter dem Mindestniveau liegt
            turnOffMsg = { payload: "OFF" };
        } else {
            // Berechnet den erforderlichen Leistungsprozentsatz, wenn keine Ausschaltanforderung vorliegt
            let requiredPercent = Math.floor(powerDifference / pwrSteps);
            let effectiveMaxOutput = socLevelBattery === 100 ? maxOutputAtFullSoc : maxOutputZeroInjection;
            requiredPercent = Math.max(minOutputZeroInjection, Math.min(requiredPercent, effectiveMaxOutput));
            setPercentMsg = { payload: requiredPercent };
        }
    } else if (socLevelBattery >= onThresholdInv && powerDifference >= minPowerInverter) {
        // Überprüft, ob der Batterie-SoC oberhalb des Schwellenwertes liegt und die Differenzleistung ausreichend ist
        let requiredPercent = Math.floor(powerDifference / pwrSteps);
        let effectiveMaxOutput = socLevelBattery === 100 ? maxOutputAtFullSoc : maxOutputZeroInjection;
        requiredPercent = Math.max(minOutputZeroInjection, Math.min(requiredPercent, effectiveMaxOutput));
        setPercentMsg = { payload: requiredPercent };
        turnOnMsg = { payload: "ON" };
    } else {
        // Keine Aktion erforderlich, da der Wechselrichter aus ist und die Bedingungen zum Einschalten nicht erfüllt sind
        debugMsg = { payload: "Wechselrichter bleibt aus - Bedingungen zum Einschalten nicht erfüllt" };
    }
}

const logFileMsg = createLogFileMsg(dtuState, invStateProducing, invStateReachable, statusZeroInjection, pwrConsumption, pwrSecondSource, socLevelBattery, setPercentMsg, turnOnMsg, turnOffMsg, debugMsg);
// Rückgabe der Steuerbefehle
return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];

// 1. DATA RETRIEVAL (Using the Map in the input message)
const ha = msg.payload;
const gridPower = parseFloat(ha["sensor.smartmeter_keller_sml_watt_summe"]?.state) || 0;
const maxChargePower = parseFloat(ha["sensor.solarflow_800_pro_charge_max_limit"]?.state) || 800;
const batteryInflow = parseFloat(ha["sensor.solarflow_800_pro_grid_input_power"]?.state) || 0;
const calculatedDemand = msg.adjustment.defensiveTarget;
const smoothedSolarPower = msg.adjustment.solarPower;
const soc = parseFloat(ha["sensor.solarflow_800_pro_electric_level"]?.state) || 0;
const minSoc = parseFloat(ha["number.solarflow_800_pro_min_soc"]?.state) || 15;
const currentSetInflow = parseFloat(ha["number.solarflow_800_pro_input_limit"]?.state) || 0;
const totalProduced = (parseFloat(ha["sensor.hoymiles600_power"]?.state) || 0) + (parseFloat(ha["sensor.wechselrichter_ac_leistung"]?.state) || 0);

// 2. CONFIGURATION (Based on safety buffer strategy)
// this addresses the "Moving Target" problem with huge latencies of smart meter and battery chargine changes:
const targetBuffer = -30;         // Aim for 30W import
const deadband = 50;              // Stability zone ignore fluctuations smaller than 50W
const maxInverterPower = 1200;    // the Inverter limit
const minSustain = 50;            // Keep charging circuit active

// calculated Demand is the brutto demand of power, solar power the generated and usable power.
// default expects, that there is more solar power than demand, 
// e.g. 1000W (solar) - 300W (demand) - (-30) = 730W to charge
//      300W (solar) - 350W (demand) - (-30) = -20W  - hardly necessary to charge but grid -10 => 40 W charge
//      200W (solar) - 200W (demand) - (-30) = 30W  to charge
//        0W (solar) - 200W (demand) - (-30) = -170W  to discharge
//        1W (solar) - 201W (demand) - (-30) = -170W  to adjust to 0 (stop charging)
//  --- SAFETY RULES & CLAMPING
let clampReason = "None";
let ruleApplied = "None";

// 3. THE CALCULATION (Grid-Anchor)
let gridGap = targetBuffer - gridPower;
let targetCharge = currentSetInflow + gridGap;
// If we are exporting (gridPower < 0), we want to be much more aggressive.
// We add a 'Proportional Boost' to the gap to overcome system latency.
if (gridPower < targetBuffer) {
    const exportIntensity = Math.abs(gridPower);
    // Increase the gap by 50% of the export to force a faster rise
    gridGap = gridGap + (exportIntensity * 0.5); 
}

// 4. SANITY CHECKS & SUSTAIN
const theoreticalSurplus = (smoothedSolarPower - calculatedDemand);
// If solar production is > 150W, we keep the charging circuit 'warm' at 50W,
// even if the house is currently importing from the grid.
const productionThreshold = 150; // Adjust this based on your 'sunny enough' preference

if (totalProduced > productionThreshold && targetCharge < minSustain) {
    targetCharge = minSustain;
    ruleApplied = "Sustain (Production)";
    // THE MISSING LINK: The "Boost"
    // If we are sustained at 50W, but we are STILL exporting (gridPower < 0),
    // we should nudge the charge up to swallow that export.
    if (gridPower < targetBuffer) {
        targetCharge = targetCharge + Math.abs(gridPower); 
        ruleApplied = "Sustain + Anti-Leak";
    }
}

// Keep the Solar Ceiling safety
const solarCeiling = theoreticalSurplus + 100; 
if (targetCharge > solarCeiling && gridPower > targetBuffer) {
    // But we don't want to charge from the grid! 
    // If targetCharge is Sustain(50) but theoreticalSurplus is -58, 
    // we need to decide if we 'waste' 50W of grid power to keep the battery warm.
    // Let's allow it ONLY if the deficit isn't massive.
    if (theoreticalSurplus < -200) { 
        targetCharge = 0; // House is too hungry, give up on sustain.
    }
}

// Minimum Sustain: If sun is out, stay at 50W even if demand is high
if (theoreticalSurplus > 10 && targetCharge < minSustain) {
    targetCharge = minSustain;
}

// Hard floor
if (targetCharge < 0) targetCharge = 0;

// 5. DYNAMIC SMOOTHING (Slew Rate)
let lastCommand = context.get('lastCommand') || 0;
// Instead of a fixed Alpha, we use a "Fast-Up, Slow-Down" approach.
let finalAlpha;
if (gridPower < targetBuffer) {
    // CRITICAL: If we are exporting, we jump to the target IMMEDIATELY
    finalAlpha = 1.0; 
} else if (targetCharge > lastCommand) {
    // If we are increasing charge (but not leaking), move fast
    finalAlpha = 0.9;
} else {
    // If we are decreasing charge, move slowly to stay "warm"
    finalAlpha = 0.2;
}
let smoothedCommand = (targetCharge * finalAlpha) + (lastCommand * (1 - finalAlpha));

// Current state: How much are we currently charging?
const currentCharging = currentSetInflow;

// Rule: Minimum SoC Recovery
if (soc <= minSoc && totalProduced >= 150) {
    const recoveryCharge = totalProduced / 2;
    if (smoothedCommand < recoveryCharge) {
        smoothedCommand = recoveryCharge;
        ruleApplied = "SoC Recovery";
    }
}

// Clamp to Hardware Limits
if (smoothedCommand > maxInverterPower) {
    smoothedCommand = maxInverterPower;
    clampReason = "Inverter Max";
}
if (smoothedCommand > maxChargePower) {
    smoothedCommand = maxChargePower;
    clampReason = "Battery Max";
}
// Rule: Hard Floor
if (smoothedCommand < 0) {
    smoothedCommand = 0;
    ruleApplied = "Floor (0W)";
}

// 7. CYCLE GUARD (Deadband)
// If we are stable and not exporting, don't update if change is tiny
const delta = Math.abs(smoothedCommand - lastCommand);
if (delta < 5 && gridPower > 0 && batteryInflow == 0) {
    node.status({ fill: "green", shape: "ring", text: `Stable @ ${Math.round(smoothedCommand)}W` });
    return null;
}

// 8. OUTPUTS & PERSISTENCE
context.set('lastCommand', smoothedCommand);
const roundedCommand = Math.round(smoothedCommand);

// Store the results in their own property, keeping the map safe
msg.adjustment.command = roundedCommand;
msg.adjustment.grid = gridPower;



// Only output if the command actually changed significantly (e.g., > 5W)
if (Math.abs(smoothedCommand - lastCommand) < 5 && gridPower > 0 && batteryInflow == 0) {
    node.status({
        fill: "green", shape: "dot", text: `Idle (deadband) - Hardly changed power - finish: ${Math.round(smoothedCommand)}W, grid Power ${gridPower}W` });
    return null;
}

// 6. FINAL OUTPUT & PERSISTENCE
context.set('lastCommand', smoothedCommand);

const insights = {
    payload: {
        timestamp: new Date().toISOString(),
        efficiency: { gridExport: gridPower < 0 ? Math.abs(gridPower) : 0, isLeaking: gridPower < targetBuffer },
        calculation: { theoreticalSurplus: Math.round(theoreticalSurplus), targetCharge: Math.round(targetCharge), finalCommand: roundedCommand },
        constraints: { clamp: clampReason, rule: ruleApplied, delta: Math.round(delta) },
        sensors: { solar: smoothedSolarPower, demand: calculatedDemand, grid: gridPower, soc: soc }
    }
};

// Update node status to show the most important "Why"
node.status({
    fill: gridPower < targetBuffer ? "red" : "green",
    shape: "dot",
    text: `Cmd: ${roundedCommand}W | Clamp: ${clampReason} | Export: ${Math.round(gridPower)}W`
});

return [msg, insights];

const map = msg.payload;
const adj = msg.adjustment;

// UNIT-AWARE FORECAST (Scaling kWh to Wh)
function getWh(entityId) {
    const entity = map[entityId];
    if (!entity) return 0;

    let value = parseFloat(entity.state) || 0;
    const unit = entity.attributes?.unit_of_measurement;

    // If the unit is kWh, multiply by 1000
    if (unit === "kWh") {
        return value * 1000;
    }
    return value; // Assume Wh otherwise
}

// 1. DYNAMIC SUN LOGIC
// Sun state: 'above_horizon' or 'below_horizon'
const sunAbove = map["sun.sun"]?.state === "above_horizon";

// 2. Soc of Battery in %
const soc = parseFloat(map["sensor.solarflow_800_pro_electric_level"]?.state) || 0;
const minimalCharge = parseFloat(map["number.solarflow_800_pro_min_soc"]?.state) || 0;

// 2. FORECAST LOGIC (Total Energy Remaining)
// Wh remaining today 
const totalSolarRemaining = getWh("sensor.energy_production_today_remaining") +
                            getWh("sensor.energy_production_today_remaining_2");

// 3. THE DECISION (The "Intelligent" Branch)
let toCharge = null;
let toDischarge = null;

/**
 * DECISION LOGIC:
 * Switch to NIGHT/DISCHARGE mode only if:
 * - Sun is down OR the total remaining forecast is negligible (< 50Wh)
 * - AND we aren't in a "Low Battery" state where we should strictly wait for sun.
 */
const isSolarDayOver = !sunAbove || (totalSolarRemaining < 50);
const batteryHasReserve = soc > minimalCharge; // Don't start discharging if battery is nearly empty

if (isSolarDayOver && batteryHasReserve) {
    toDischarge = msg;
    node.status({ fill: "blue", shape: "dot", text: `Discharge - Night, remaing solar ${totalSolarRemaining}Wh, Solar Day is Over: ${isSolarDayOver}, battery has res: ${batteryHasReserve}` });
} else if (adj.solarPower > 0) {
    toCharge = msg;
    node.status({ fill: "yellow", shape: "dot", text: `Charge - Day/Solar: remaing solar ${totalSolarRemaining}Wh` });
} else {
    node.status({ fill: "red", shape: "dot", text: `Empty Battery, no solar power: ${adj.solarPower}W, solar forecast ${totalSolarRemaining}Wh, battery soc: ${soc}` });
}


return [toCharge, toDischarge];

const map = msg.payload;
const adj = msg.adjustment; // Contains .command, .requiredChange, and .grid

// 1. DATA EXTRACTION FROM MAP
const soc = parseFloat(map["sensor.solarflow_800_pro_electric_level"]?.state) || 0;
const maxSoc = parseFloat(map["number.solarflow_800_pro_soc_set"]?.state) || 100; // Your threshold
const currentInflow = parseFloat(map["sensor.solarflow_800_pro_grid_input_power"]?.state) || 0;
const currentSetInflow = parseFloat(map["number.solarflow_800_pro_input_limit"]?.state) || 0;
const maxChargeHardware = parseFloat(map["sensor.solarflow_800_pro_charge_max_limit"]?.attributes?.max) || 800;

// 2. CORE CALCULATION
// adj.command is negative when we have to charge the battery with solar power
let targetCharge = Math.abs(adj.command);

// Add a safety check: If Actual and Set are miles apart (e.g. communication error),
// fallback to a more conservative average.
// To INCREASE charging, we subtract the negative error (e.g., 100 - (-200) = 300)
const gap = Math.abs(currentSetInflow - currentInflow);
if (gap > 100) {
    // Something is wrong (communication lag or manual override)
    // Fallback to Actual to be safe
}

// 3. APPLY RULES & SAFETY
let reason = "Adjusting normally";

// Check: Battery Full
if (soc + 1.1 > maxSoc) {
    targetCharge = 0;
    reason = "BATTERY_FULL_OVERFLOW";
} else if ( targetCharge > maxChargeHardware ) {
    reason = "MAX_CHARGE_OVERFLOW";
}

// Rule: Hardware Limits
targetCharge = Math.max(0, Math.min(maxChargeHardware, targetCharge));

// 4. LOGGING & OUTPUT
const logMsg = {
    payload: {
        time: new Date().toLocaleString('de-DE'),
        grid: adj.grid,
        soc: soc,
        targetCharge: Math.round(targetCharge),
        reason: reason
    }
};

// Only trigger the hardware if the change is significant (> 10W)
let hardwareCmd = null;
if (Math.abs(targetCharge - currentSetInflow) > 10) {
    hardwareCmd = { payload: Math.round(targetCharge) };
}
else {
    reason = "No change - no need to adjust"
}

node.status({ fill: "green", shape: "dot", text: `${Math.round(targetCharge)}W (${reason})` });

return [hardwareCmd, { payload: reason }, logMsg];

// 1. DATA FROM PREVIOUS NODES
const action = msg.payload;
const exportPower = msg.gridExport || 0; // The extra W we can't store
const now = Date.now();

// 2. STATE PERSISTENCE (Track status of loads)
let loads = context.get('loads') || {
    dryer: { active: false, lastChange: 0, power: 250, entity: "switch.dryer" },
    dehumidifier: { active: false, lastChange: 0, power: 150, entity: "switch.dehumidifier" }
};

// 3. MINIMUM RUN TIME (Safety: 15 minutes)
const minRunTime = 15 * 60 * 1000;

// 4. LOGIC: ADDING LOADS (Turn ON)
if (action.includes("OVERFLOW")) {
    // Try to turn on the first available load in order of priority
    if (!loads.dehumidifier.active && exportPower > loads.dehumidifier.power + 50) {
        loads.dehumidifier.active = true;
        loads.dehumidifier.lastChange = now;
        node.send({ payload: "ON", topic: loads.dehumidifier.entity });
    }
    else if (!loads.dryer.active && exportPower > loads.dryer.power + 100) {
        loads.dryer.active = true;
        loads.dryer.lastChange = now;
        node.send({ payload: "ON", topic: loads.dryer.entity });
    }
}

// 5. LOGIC: REMOVING LOADS (Turn OFF)
// If we are back to NORMAL (importing or zero), check if we need to shed load
if (action === "NORMAL" || exportPower < 20) {
    // Turn off in reverse order, but only if they've run long enough
    if (loads.dryer.active && (now - loads.dryer.lastChange) > minRunTime) {
        loads.dryer.active = false;
        node.send({ payload: "OFF", topic: loads.dryer.entity });
    }
    else if (loads.dehumidifier.active && (now - loads.dehumidifier.lastChange) > minRunTime) {
        loads.dehumidifier.active = false;
        node.send({ payload: "OFF", topic: loads.dehumidifier.entity });
    }
}

context.set('loads', loads);
node.status({ fill: loads.dryer.active ? "green" : "grey", shape: "dot", text: `Dryer: ${loads.dryer.active} | Dehum: ${loads.dehumidifier.active}` });

const map = msg.payload;
const adj = msg.adjustment;

const currentSetLimit = parseFloat(map["number.solarflow_800_pro_output_limit"]?.state) || 0;

// 1. CHOOSE THE TARGET
// We want to reach the 'forcedRate' (to empty the battery),
// OR follow the 'defensiveTarget' (5-min average) if the house is active.
let targetDischarge = adj.command;

// 2. HARDWARE OUTPUT
let hardwareCmd = null;
if (Math.abs(targetDischarge - currentSetLimit) > 5) {
    hardwareCmd = { payload: Math.round(targetDischarge) };
}

node.status({
    fill: "blue",
    shape: adj.nextHourSolar > 50 ? "ring" : "dot",
    text: `target: ${Math.round(targetDischarge)}W`
});

return [hardwareCmd];

// 1. Calculate current real house demand
const map = msg.payload;
// INITIALIZATION: Ensure msg.adjustment exists so we don't crash
if (!msg.adjustment) {
    msg.adjustment = {};
}

const grid = parseFloat(map["sensor.smartmeter_keller_sml_watt_summe"]?.state) || 0;
const batOut = parseFloat(map["sensor.solarflow_800_pro_output_home_power"]?.state) || 0;
const solarIn1 = parseFloat(map["sensor.wechselrichter_ac_leistung"]?.state) || 0;
const solarIn2 = parseFloat(map["sensor.hoymiles600_power"]?.state) || 0;
const batIn = parseFloat(map["sensor.solarflow_800_pro_grid_input_power"]?.state) || 0;
const currentDemand = grid + batOut + solarIn1 + solarIn2 - batIn;
const currentSolarPower = solarIn1 + solarIn2;

// 2. Manage 5-minute history (15 samples @ 20s interval)
let history = context.get('demandHistory') || [];
history.push(currentDemand);
if (history.length > 15) 
    history.shift();
context.set('demandHistory', history);
let solarHistory = context.get('solarHistory') || [];
solarHistory.push(currentSolarPower);
if (solarHistory.length > 15) 
    solarHistory.shift();
context.set('solarHistory', solarHistory);

// 3. Calculate Average
const averageDemand = history.reduce((a, b) => a + b, 0) / history.length;
const averageSolar = solarHistory.reduce((c, d) => c + d, 0) / solarHistory.length;
// 4. Calculate Median (P50)
// We create a copy so we don't mess up the chronological history
const sorted = [...history].sort((a, b) => a - b);
const lowMiddle = Math.floor((sorted.length - 1) / 2);
const highMiddle = Math.ceil((sorted.length - 1) / 2);
const medianDemand = (sorted[lowMiddle] + sorted[highMiddle]) / 2;
const sortedSolar = [...solarHistory].sort((a, b) => a - b);
const lowMiddleSol = Math.floor((sortedSolar.length - 1) / 2);
const highMiddleSol = Math.ceil((sortedSolar.length - 1) / 2);
const medianSolar = (sortedSolar[lowMiddleSol] + sortedSolar[highMiddleSol]) / 2;

// 5. ASYMMETRIC LOGIC
// Demand: Use the Median/Defensive approach (STAY SLOW)
// This prevents the battery from discharging too fast when a spike is brief.
const defensiveTarget = Math.min(medianDemand, currentDemand);

// Solar: Use the INSTANT value for charging (STAY FAST)
// If the sun is there NOW, we want to capture it NOW.
const proactiveSolar = currentSolarPower;

// 6. THE "CONTINUOUS FLOW" BIAS
// If there is any solar production (>50W), we artificially lower the 
// defensive demand slightly to ensure the calculation always results 
// in a small positive "surplus" for the battery.
const flowBias = (proactiveSolar > 50) ? 20 : 0; 

node.status({
    fill: "blue", 
    shape: "dot", 
    text: `Solar (Now): ${Math.round(proactiveSolar)}W, (median): ${Math.round(medianSolar)}W | Demand (Def): ${Math.round(defensiveTarget)}W, (5min average): ${Math.round(medianDemand)}W`
});

msg.adjustment.defensiveTarget = Math.round(defensiveTarget - flowBias);
msg.adjustment.solarPower = Math.round(proactiveSolar);
msg.adjustment.solarAveragePower = Math.round(medianSolar);
return msg;

const map = msg.payload;

// 1. DATA EXTRACTION
const soc = parseFloat(map["sensor.solarflow_800_pro_electric_level"]?.state) || 0;
const availableWh = (parseFloat(map["sensor.solarflow_800_pro_available_kwh"]?.state) || 0) * 1000;
const totalCapacity = 1980; // Wh (Adjust to your actual battery size, Zendure does not expose values)

// 2. NEXT HOUR FORECAST (Wh expected in the next 60 mins)
const nextH1 = parseFloat(map["sensor.energy_next_hour"]?.state) || 0;
const nextH2 = parseFloat(map["sensor.energy_next_hour_2"]?.state) || 0;
const totalNextHourWh = nextH1 + nextH2;

// 3. TIME CALCULATION
const now = new Date().getTime();
const sunrise = new Date(map["sun.sun"]?.attributes?.next_rising).getTime();

// 4. DYNAMIC WINDOW ADJUSTMENT
let hoursToUsableSolar = Math.max(0.5, (sunrise - now) / (1000 * 60 * 60));

// If the Next Hour forecast is already > 50Wh, the sun is effectively "up" 
// for the battery logic, even if the clock says it's early.
if (totalNextHourWh > 100) {
    // Sun is strong! Shorten the window to 1 hour to empty the battery faster.
    hoursToUsableSolar = 1.0;
} else if (totalNextHourWh > 20) {
    // Sun is starting to peek through.
    hoursToUsableSolar = Math.min(hoursToUsableSolar, 2.0);
}

// Handle edge case: If it's 2 AM and sunrise is 6 AM, hoursToSunrise = 4.
// If sunrise has already passed or is invalid, default to a small number to avoid division by zero.
// Calculate hours only if we have a valid date
let hoursToSunrise = 0.5; // Default safety
if (!isNaN(sunrise)) {
    // Math.max ensures we don't get negative numbers if sunrise just happened
    hoursToSunrise = Math.max(0.5, (sunrise - now) / (1000 * 60 * 60));
}

// 3. CALCULATION
const usableWh = Math.max(0, availableWh);
const forcedRate = Math.round(usableWh / hoursToUsableSolar);

// 4. PASS IT FORWARD
msg.adjustment.forcedRate = forcedRate;
msg.adjustment.hoursToSunrise = hoursToSunrise.toFixed(1);
msg.adjustment.nextHourSolar = totalNextHourWh;

node.status({ fill: "blue", shape: "ring", text: `Budget: forced ${forcedRate}W until sunrise` });

return msg;

// 1. DATA RETRIEVAL (Using the Map in the input message)
const ha = msg.payload;
const adj = msg.adjustment;


// Get numeric values from Home Assistant collection (handling "unavailable" with || 0)
const gridPower = parseFloat(ha["sensor.smartmeter_keller_sml_watt_summe"]?.state) || 0; 
const currentBatteryOut = parseFloat(ha["sensor.solarflow_800_pro_output_home_power"]?.state) || 0;
const maxChargePower = parseFloat(ha["sensor.solarflow_800_pro_charge_max_limit"]?.state) || 800;
const batteryInflow = parseFloat(ha["sensor.solarflow_800_pro_grid_input_power"]?.state) || 0;
const calculatedDemand = msg.adjustment.defensiveTarget;
const smoothedSolarPower = msg.adjustment.solarPower;
const forcedDischarge = msg.adjustment.forcedRate;

// 2. CONFIGURATION (Based on safety buffer strategy)
// this addresses the "Moving Target" problem with huge latencies of smart meter and battery chargine changes:
//   1. The Deadband(deadband = 75): This is your Cycle - Killer.
//                                   It stops the battery from chasing the "ghosts" of small appliances.
//                                   If your fridge compressor flickers, the battery ignores it.
//
//   2. The Safety Buffer(-30): By aiming for a 30W import, you create a "cushion." 
//                              When a cloud disappears and solar spikes, you have 30W of "room" before
//                              starting to feed-in into public grid.
//
//   3. The EMA(alpha = 0.9): This solves the 50s latency of smart meter and battery.
//                            Instead of jumping to a new value every 20s (init trigger) and
//                            overshooting, the battery "slides" toward the new value. This reduces the 
//                            chemical stress on the LiFePO4 cells.

const targetBuffer = -50;         // Aim for 50W import to prevent feed-in
const deadband = 50;              // Ignore fluctuations smaller than 50W
const alpha = 0.3;                // EMA Smoothing factor (0.1 = very slow, 0.9 = very fast)

// 3. CALCULATION
// calculated Demand is the brutto demand of power, solar power the generated and usable power.
// default expects, that there is more solar power than demand, 
// e.g. 10W (solar) - 300W (demand) - (-30) = -260W to discharge
//       0W (solar) - 50W (demand) - (-30) = -20W to discharge
//     100W (solar) - 200W (demand) - (-30) = -70W to discharge
//       0W (solar) - 200W (demand) - (-30) = -170W to discharge
//       1W (solar) - 201W (demand) - (-30) = -170W to discharge
//       0W (solar) - (-50)W (demand) - (-30) = 80W to adjust or even stop discharging (discharging is at least 50W)
let requiredChange = (smoothedSolarPower - calculatedDemand) - targetBuffer;

// 4. THE CYCLE GUARD (Dynamic Deadband)
// If the requiredChange is small AND we aren't "exporting", stay still to save battery cycles
if (Math.abs(requiredChange) < deadband && gridPower > 0 && currentBatteryOut == 0) {
    node.status({ fill: "green", shape: "dot", text: `Done (deadband) - Stable power - finish (calculated change is ${Math.round(requiredChange)}W, grid power: ${Math.round(gridPower)}W)` });
    return null; // Stop the message here; no command sent to inverter
}

// 5. EMA SMOOTHING (The "Lag Compensator")
let lastCommand = context.get('lastCommand') || 0;
let rawCommand = requiredChange * -1; // invert to represent the power gap required from battery

if (rawCommand < 0 && currentBatteryOut > 0) { // demand is larger than solar power but still solar power available
    rawCommand = (requiredChange - targetBuffer - currentBatteryOut) * -1; // 80W - 30 - 60 = -10 -> reduce discharging before stopping
}

// Apply Exponential Moving Average
let smoothedCommand = (rawCommand * alpha) + (lastCommand * (1 - alpha));

// 5. THE ZERO-EXPORT DEFENSE (The "No-Penalty" Guard)
// --> EMERGENCY BRAKE
if (gridPower < 0) {
    smoothedCommand = Math.max(0, currentBatteryOut + gridPower + targetBuffer);
}

smoothedCommand = Math.min(smoothedCommand, forcedDischarge * 2.5);

// Only output if the command actually changed significantly (e.g., > 5W)
if (Math.abs(smoothedCommand - lastCommand) < 5 && gridPower > 0 && currentBatteryOut == 0) {
    node.status({
        fill: "green", shape: "dot", text: `Idle (deadband) - Hardly changed power - finish: ${Math.round(smoothedCommand)}W, grid Power ${gridPower}W` });
    return null;
}

// 6. FINAL OUTPUT & PERSISTENCE
context.set('lastCommand', smoothedCommand);

// Store the results in their own property, keeping the map safe
msg.adjustment = {
    command: Math.round(smoothedCommand),
    requiredChange: requiredChange, // The raw error before smoothing
    isStable: Math.abs(requiredChange) < deadband,
    grid: gridPower
};

// Now msg.payload still contains 31 entities, 
// and msg.adjustment contains this logic results.
node.status({ fill: "green", shape: "dot", text: `Calculated Power (smoothed): ${Math.round(smoothedCommand)}W` });
return msg;
